import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { CartProvider } from './context/CartContext';

import Header from './components/Header';
import Home from './components/Home';
import Login from './components/Login';
import Registro from './components/Registro';
import Dashboard from './components/Dashboard';
import GestionOfertas from './components/GestionOfertas';
import PanelCliente from './components/PanelCliente';

const RutaPrivada = ({ children, rolRequerido }) => {
  const { user, loading } = useAuth();
  if (loading) return <div style={spinnerStyle}>Cargando aplicación...</div>;
  if (!user) return <Navigate to="/login" />;
  if (rolRequerido && user.rol !== rolRequerido) return <Navigate to="/" />;
  return children;
};

function App() {
  return (
    <AuthProvider>
      <CartProvider>
        <Router>
          <Header /> 
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/login" element={<Login />} />
            <Route path="/registro" element={<Registro />} />

            <Route path="/dashboard" element={
              <RutaPrivada rolRequerido="vendedor"><Dashboard /></RutaPrivada>
            } />

            <Route path="/ofertas/:id" element={
              <RutaPrivada rolRequerido="vendedor"><GestionOfertas /></RutaPrivada>
            } />

            <Route path="/panel-cliente" element={
              <RutaPrivada rolRequerido="cliente"><PanelCliente /></RutaPrivada>
            } />

            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </Router>
      </CartProvider>
    </AuthProvider>
  );
}

const spinnerStyle = { display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh', fontSize: '1.2rem', color: '#e67e22', fontWeight: 'bold' };

export default App;
